export default function App() {
  const [state, dispatch] = useReducer(authReducer, initialAuthState);

  useEffect(() => {
    let mounted = true;
    (async () => {
      try {
        const session = await readSession();
        if (!mounted) return;

        if (session?.token && session?.user) {
          try {
            const refreshed = await apiRefreshToken(session.token);
            const nextSession = { ...session, token: refreshed.token };
            await persistSession(nextSession);
            dispatch({ type: "BOOTSTRAP_DONE", payload: nextSession });
          } catch {
            await clearSession();
            dispatch({ type: "BOOTSTRAP_DONE", payload: null });
          }
        } else {
          dispatch({ type: "BOOTSTRAP_DONE", payload: null });
        }
      } catch {
        dispatch({ type: "BOOTSTRAP_DONE", payload: null });
      }
    })();
    return () => {
      mounted = false;
    };
  }, []);

  const auth = useMemo(() => {
    return {
      token: state.token,
      user: state.user,
      isAuthenticated: !!state.token,
      signIn: async ({ email, password }) => {
        const res = await apiLogin({ email, password });
        const session = { token: res.token, user: res.user };
        await persistSession(session);
        dispatch({ type: "SIGN_IN", payload: session });
      },
      signOut: async () => {
        await clearSession();
        dispatch({ type: "SIGN_OUT" });
      },
      updateUser: async (partialUser) => {
        const nextUser = { ...(state.user || {}), ...(partialUser || {}) };
        const session = { token: state.token, user: nextUser };
        await persistSession(session);
        dispatch({ type: "UPDATE_USER", payload: partialUser });
      },
    };
  }, [state.token, state.user]);

  if (state.isBootstrapping) return <SplashScreen />;

  return (
    <AuthContext.Provider value={auth}>
      <NavigationContainer>
        {auth.isAuthenticated ? <AppStack /> : <AuthStack />}
      </NavigationContainer>
    </AuthContext.Provider>
  );
}

